#include <vector>
#include <queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    priority_queue<tuple<long long, long long, long long, long long>, vector<tuple<long long, long long, long long, long long>>, greater<tuple<long long, long long, long long, long long>>> pq;

    // Initial state: (cost, time_mod_2, i, j)
    long long initial_cost = (0 + 1) * (0 + 1);
    dist[0][0][1] = initial_cost;
    pq.push({initial_cost, 1, 0, 0});

    int dirs[2][2] = {{0, 1}, {1, 0}}; // right, down

    while (!pq.empty()) {
        auto [current_cost, time_mod, i, j] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (time_mod == 1) { // odd time: move
            for (auto &dir : dirs) {
                long long ni = i + dir[0];
                long long nj = j + dir[1];
                if (ni < m && nj < n) {
                    long long move_cost = (ni + 1) * (nj + 1);
                    long long new_cost = current_cost + move_cost;
                    long long new_time_mod = (time_mod + 1) % 2;
                    if (new_cost < dist[ni][nj][new_time_mod]) {
                        dist[ni][nj][new_time_mod] = new_cost;
                        pq.push({new_cost, new_time_mod, ni, nj});
                    }
                }
            }
        } else { // even time: wait
            long long wait_cost = waitCost[i][j];
            long long new_cost = current_cost + wait_cost;
            long long new_time_mod = (time_mod + 1) % 2;
            if (new_cost < dist[i][j][new_time_mod]) {
                dist[i][j][new_time_mod] = new_cost;
                pq.push({new_cost, new_time_mod, i, j});
            }
        }
    }

    return -1; // unreachable
}

