}
func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	if m == 0 || n == 0 {
		return 0
	}

	dist := make([][][]int64, m)
	for i := range dist {
		dist[i] = make([][]int64, n)
		for j := range dist[i] {
			dist[i][j] = make([]int64, 2)
			dist[i][j][0] = 1 << 62
			dist[i][j][1] = 1 << 62
		}
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)

	initialCost := (0 + 1) * (0 + 1)
	dist[0][0][1] = initialCost
	heap.Push(&pq, State{initialCost, 1, 0, 0})

	dirs := [][]int64{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(State)
		currentCost, timeMod, i, j := current.cost, current.timeMod, current.i, current.j

		if i == m-1 && j == n-1 {
			return currentCost
		}

		if timeMod == 1 {
			for _, dir := range dirs {
				ni := i + dir[0]
				nj := j + dir[1]
				if ni < m && nj < n {
					moveCost := (ni + 1) * (nj + 1)
					newCost := currentCost + moveCost
					newTimeMod := (timeMod + 1) % 2
					if newCost < dist[ni][nj][newTimeMod] {
						dist[ni][nj][newTimeMod] = newCost
						heap.Push(&pq, State{newCost, newTimeMod, ni, nj})
					}
				}
			}
		} else {
			waitCost := waitCost[i][j]
			newCost := currentCost + waitCost
			newTimeMod := (timeMod + 1) % 2
			if newCost < dist[i][j][newTimeMod] {
				dist[i][j][newTimeMod] = newCost
				heap.Push(&pq, State{newCost, newTimeMod, i, j})
			}
		}
	}

	return -1
}
